class Solution(object):
    def findKDistantIndices(self, nums, key, k):
        result = set()
        for j in range(len(nums)):
            if nums[j] == key:
                for i in range(max(0, j - k), min(len(nums), j + k + 1)):
                    result.add(i)
        return sorted(result)
